import { test, expect } from '@playwright/test';
import crypto from 'node:crypto';
import fs from 'node:fs';
import path from 'node:path';

const ASSISTANT_RESPONSE_TIMEOUT_MS = 60000;
const TEST_CASE_TIMEOUT_MS = 120000;
const STREAM_REQUEST_TIMEOUT_MS = 15000;

/* Failure Taxonomy:
 * RUNNER_SELECTOR_FAILURE  — Playwright could not find expected DOM element
 * RUNNER_WAIT_FAILURE      — Wait condition did not resolve
 * RUNNER_STREAM_TIMEOUT    — Stream request was not observed
 * FRONTEND_NOT_READY       — Frontend DOM or dev server not available (handled by playwright.config.js webServer)
 * BACKEND_HEALTH_FAIL      — Backend /api/health did not respond (handled by playwright.config.js webServer)
 * INFRASTRUCTURE_OFFLINE   — ERR_CONNECTION_REFUSED (or equivalent) reaching baseUrl in beforeEach page.goto; run npm run start-dev
 * PROVIDER_TIMEOUT         — LLM provider did not respond within expected time
 * TOOL_ROUTING_FAILURE     — Wrong or no tool was called for the prompt (BACKLOG-028)
 * TOOL_ROUTING_PASS        — Expected tool was triggered (success classification for routing-only tests)
 * ASSERTION_MISMATCH       — Response text did not match expected assertions
 */


function base64Url(input) {
  return Buffer.from(input)
    .toString('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
}

function loadJanusAppDataConfig() {
  const appData = process.env.APPDATA || '';
  const configPath = path.join(appData, 'Janus Projekt', 'config.json');
  return { configPath, config: JSON.parse(fs.readFileSync(configPath, 'utf-8')) };
}

function createE2eJwt() {
  const { configPath, config } = loadJanusAppDataConfig();
  const secret = config.jwt_secret_key;
  if (!secret) throw new Error(`jwt_secret_key missing in ${configPath}`);

  const header = { alg: 'HS256', typ: 'JWT' };
  const payload = {
    sub: 'local_user',
    scopes: ['me', 'settings:write'],
    exp: Math.floor(Date.now() / 1000) + 60 * 60,
  };
  const unsigned = `${base64Url(JSON.stringify(header))}.${base64Url(JSON.stringify(payload))}`;
  const signature = crypto
    .createHmac('sha256', secret)
    .update(unsigned)
    .digest('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
  return `${unsigned}.${signature}`;
}

async function installInternalApiKeyRoute(page, internalKey) {
  if (!internalKey) {
    throw new Error('api_key missing in Janus config.json (required for E2E against real backend)');
  }
  const handler = async (route) => {
    const headers = { ...route.request().headers() };
    headers['X-Janus-Internal-Key'] = internalKey;
    await route.continue({ headers });
  };
  await page.route('http://127.0.0.1:8001/api/**', handler);
  await page.route('http://localhost:8001/api/**', handler);
}

function chatWindow(page, windowName) {
  return page.getByRole('region', { name: `Chat-Fenster ${windowName}` });
}

function chatInput(page, windowName) {
  return chatWindow(page, windowName).getByPlaceholder(/Nachricht an Janus senden/);
}

function assistantResponse(page, windowName) {
  return page.locator(`#chat-messages-${windowName} .message.assistant`).last();
}

function compactApiUrl(url) {
  try {
    const parsed = new URL(url);
    return `${parsed.origin}${parsed.pathname}`;
  } catch {
    return url;
  }
}

/** Strategy registry: model_selection_v2_5 — header LLM dropdowns per chat window.
 *  Catalog load: frontend/js/app.js loadModelCatalog() (shared appState.model_catalog).
 *  DOM refresh: document CustomEvent "models-updated" (e.g. settings.js after model save).
 *  V2.5: Header provider "" = inherit sidebar ("↳ Wie Sidebar"); sendMessage uses window-state
 *  (see chat.js effectiveProviderModelForWindow). Playwright selectOption alone can leave
 *  w.provider/w.modelId stale — we commit values with dispatchEvent("change").
 */
function resolveHeaderProviderValue(providerHint, modelId) {
  const ph = String(providerHint || '').trim();
  if (ph === 'GPT') return 'openai';
  if (ph === 'Gemini') return 'gemini';
  const m = String(modelId || '').toLowerCase();
  if (m.includes('gemini')) return 'gemini';
  return 'openai';
}

async function logModelDropdownDiagnostics(page, windowName, modelId, label) {
  try {
    const snap = await page.evaluate((wid) => {
      const sel = document.getElementById('chat-header-model-' + wid);
      if (!sel) return '<MISSING #chat-header-model-' + wid + '>';
      const prov = document.getElementById('chat-header-provider-' + wid);
      return {
        modelOuter: sel.outerHTML.slice(0, 14000),
        providerValue: prov ? prov.value : null,
        optionCount: sel.options ? sel.options.length : 0,
        optionValues: sel.options ? Array.from(sel.options).map((o) => o.value) : [],
      };
    }, windowName);
    console.error('[E2E-DIAG] selectModel failure ' + label + ' model=' + modelId + ' snapshot:', JSON.stringify(snap));
  } catch (diagErr) {
    console.error('[E2E-DIAG] selectModel diagnostics failed:', String((diagErr && diagErr.message) || diagErr));
  }
}

/** Wait up to capMs ms for a models-updated event (non-blocking if catalog already applied). */
async function waitForModelsUpdatedSignal(page, capMs) {
  const cap = typeof capMs === 'number' ? capMs : 2500;
  try {
    await page.evaluate(
      (ms) =>
        new Promise((resolve) => {
          let settled = false;
          const finish = () => {
            if (settled) return;
            settled = true;
            document.removeEventListener('models-updated', onEvt);
            clearTimeout(t);
            resolve(null);
          };
          const onEvt = () => finish();
          const t = setTimeout(finish, ms);
          document.addEventListener('models-updated', onEvt, { once: true });
        }),
      cap,
    );
  } catch (_) {
    /* ignore */
  }
}

/** Ensure AppData config lists the planned model for this provider so header <select> can populate (fillModelOptionsIntoSelect). */
async function ensureProviderModelSelection(page, providerValue, modelId) {
  try {
    const token = await page.evaluate(() => localStorage.getItem('auth_token'));
    if (!token) return;
    const res = await page.request.post('http://127.0.0.1:8001/api/models/selection', {
      headers: {
        Authorization: 'Bearer ' + token,
        'Content-Type': 'application/json',
      },
      data: JSON.stringify({ provider: providerValue, models: [modelId] }),
    });
    if (!res.ok()) {
      console.warn('[E2E-DIAG] ensureProviderModelSelection POST failed', res.status(), await res.text().catch(() => ''));
      return;
    }
    await page.evaluate(() => document.dispatchEvent(new CustomEvent('models-updated')));
    await page.waitForFunction(
      ([pv, mid]) => {
        const us = typeof window !== 'undefined' && window.appState && window.appState.user_selections && window.appState.user_selections[pv];
        return Array.isArray(us) && us.includes(mid);
      },
      [providerValue, modelId],
      { timeout: 20000 },
    );
  } catch (e) {
    console.warn('[E2E-DIAG] ensureProviderModelSelection', String((e && e.message) || e));
  }
}

async function selectModel(page, windowName, modelId, providerHint) {
  console.log('[E2E-DIAG] Selecting model (V2.5): ' + modelId);
  const providerValue = resolveHeaderProviderValue(providerHint, modelId);
  const provSel = page.locator('#chat-header-provider-' + windowName);
  const modSel = page.locator('#chat-header-model-' + windowName);
  const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

  /** Break "↳ Wie Sidebar" inheritance: commit #chat-header-provider-* so window-state has a real provider. */
  async function commitHeaderProvider(wid, pv) {
    await page.evaluate(
      ([w, p]) => {
        const hp = document.getElementById('chat-header-provider-' + w);
        if (!hp) throw new Error('MISSING_HEADER_PROVIDER');
        const want = String(p || '').trim();
        if (!want) throw new Error('EMPTY_PROVIDER');
        const idx = [...hp.options].findIndex((o) => o.value === want);
        if (idx < 0) {
          const vals = [...hp.options].map((o) => o.value + ':' + String(o.textContent || '').slice(0, 48));
          throw new Error('PROVIDER_OPTION_MISSING:' + want + ':' + JSON.stringify(vals));
        }
        hp.selectedIndex = idx;
        hp.value = want;
        hp.dispatchEvent(new Event('input', { bubbles: true }));
        hp.dispatchEvent(new Event('change', { bubbles: true }));
      },
      [wid, pv],
    );
  }

  /** Must fire change so setWindowModel runs; otherwise effectiveProviderModelForWindow keeps sidebar model. */
  async function commitHeaderModel(wid, mid) {
    await page.evaluate(
      ([w, m]) => {
        const hm = document.getElementById('chat-header-model-' + w);
        if (!hm) throw new Error('MISSING_HEADER_MODEL');
        const want = String(m || '').trim();
        if (!want) throw new Error('EMPTY_MODEL_ID');
        const idx = [...hm.options].findIndex((o) => o.value === want);
        if (idx < 0) {
          const vals = [...hm.options].map((o) => o.value);
          throw new Error('MODEL_OPTION_MISSING:' + want + ':' + JSON.stringify(vals));
        }
        hm.selectedIndex = idx;
        hm.value = want;
        hm.dispatchEvent(new Event('input', { bubbles: true }));
        hm.dispatchEvent(new Event('change', { bubbles: true }));
      },
      [wid, mid],
    );
  }

  await page.waitForFunction(
    () => {
      const overlays = document.querySelectorAll('.modal-overlay, .loading-screen, [role="dialog"][aria-modal="true"]');
      for (let i = 0; i < overlays.length; i++) {
        const el = overlays[i];
        const s = getComputedStyle(el);
        if (s.display !== 'none' && s.visibility !== 'hidden') {
          const r = el.getBoundingClientRect();
          if (r.width > 0 && r.height > 0) return false;
        }
      }
      return true;
    },
    { timeout: 15000 },
  );

  await expect(provSel).toBeVisible({ timeout: 15000 });
  await expect(modSel).toBeVisible({ timeout: 15000 });

  await ensureProviderModelSelection(page, providerValue, modelId);

  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      console.log('[E2E-DIAG] selectModel V2.5 attempt ' + attempt + ' provider=' + providerValue + ' model=' + modelId);
      await waitForModelsUpdatedSignal(page, 400);
      await commitHeaderProvider(windowName, providerValue);
      await sleep(150);

      // Wait until catalog + user_selections produced a real model list for this provider (not only inherit/placeholder).
      await page.waitForFunction(
        ([wid, pv, mid]) => {
          const hp = document.getElementById('chat-header-provider-' + wid);
          const hm = document.getElementById('chat-header-model-' + wid);
          if (!hp || !hm || !hm.options || hm.options.length === 0) return false;
          if (hp.value !== pv) return false;
          const onlyNoModels =
            hm.options.length === 1 && String(hm.options[0].textContent || '').includes('Keine Modelle');
          if (onlyNoModels) return false;
          return Array.from(hm.options).some((o) => o.value === mid);
        },
        [windowName, providerValue, modelId],
        { timeout: Math.max(20000, TEST_CASE_TIMEOUT_MS - 10000) },
      );

      await commitHeaderModel(windowName, modelId);
      await sleep(100);

      const ok = await page.evaluate(
        ([wid, pv, mid]) => {
          const hp = document.getElementById('chat-header-provider-' + wid);
          const hm = document.getElementById('chat-header-model-' + wid);
          return !!(hp && hm && hp.value === pv && hm.value === mid);
        },
        [windowName, providerValue, modelId],
      );
      if (!ok) {
        throw new Error('RUNNER_WAIT_FAILURE: header LLM selects did not settle to provider=' + providerValue + ' model=' + modelId);
      }

      console.log('[E2E-DIAG] selectModel ok: ' + modelId + ' (attempt ' + attempt + ')');
      return;
    } catch (e) {
      const msg = String((e && e.message) || e);
      console.log('[E2E-DIAG] selectModel attempt ' + attempt + ' failed: ' + msg);
      await logModelDropdownDiagnostics(page, windowName, modelId, 'attempt-' + attempt);
      if (attempt === 3) throw e;
      await sleep(400);
      await waitForModelsUpdatedSignal(page, 3000);
    }
  }
}

async function waitSendButtonReady(page, windowName) {
  const btn = page.locator('#send-button-' + windowName);
  await expect(btn).toBeVisible({ timeout: 15000 });
  await page.waitForFunction(
    (wid) => {
      const btnEl = document.getElementById('send-button-' + wid);
      if (!btnEl || btnEl.disabled || btnEl.getAttribute('aria-disabled') === 'true') return false;
      const busy = document.querySelector('[aria-busy="true"]');
      if (busy) {
        const br = busy.getBoundingClientRect();
        const bs = getComputedStyle(busy);
        if (bs.display !== 'none' && bs.visibility !== 'hidden' && br.width > 0 && br.height > 0) return false;
      }
      const modals = document.querySelectorAll(
        '.modal-overlay:not([hidden]), .modal.show, dialog[open], [role="dialog"][aria-modal="true"]',
      );
      for (let i = 0; i < modals.length; i++) {
        const el = modals[i];
        const s = getComputedStyle(el);
        if (s.display === 'none' || s.visibility === 'hidden' || s.pointerEvents === 'none') continue;
        const r = el.getBoundingClientRect();
        if (r.width > 24 && r.height > 24) return false;
      }
      return true;
    },
    windowName,
    { timeout: 30000 },
  );
  await expect(btn).toBeEnabled({ timeout: 10000 });
}


function createPromptDiagnostics(page) {
  const events = [];
  const consoleLogs = [];
  const pushEvent = (event) => {
    events.push({ timestamp: new Date().toISOString(), ...event });
    if (events.length > 200) events.shift();
  };
  const pushConsoleLog = (log) => {
    consoleLogs.push({ timestamp: new Date().toISOString(), ...log });
    if (consoleLogs.length > 400) consoleLogs.shift();
  };

  const onRequest = (request) => {
    const url = request.url();
    if (!url.includes('/api/')) return;
    pushEvent({ type: 'request', method: request.method(), url: compactApiUrl(url) });
  };
  const onResponse = (response) => {
    const url = response.url();
    if (!url.includes('/api/')) return;
    pushEvent({ type: 'response', status: response.status(), url: compactApiUrl(url) });
  };
  const onRequestFailed = (request) => {
    const url = request.url();
    if (!url.includes('/api/')) return;
    pushEvent({
      type: 'requestfailed',
      method: request.method(),
      url: compactApiUrl(url),
      failure: request.failure()?.errorText || 'unknown',
    });
  };
  const onConsole = (message) => {
    const text = message.text();
    pushConsoleLog({ type: message.type(), text: text.slice(0, 1000) });
    if (!['error', 'warning'].includes(message.type())) return;
    pushEvent({ type: `console:${message.type()}`, text: text.slice(0, 500) });
  };
  const onPageError = (error) => {
    pushEvent({ type: 'pageerror', text: String(error?.message || error).slice(0, 500) });
  };

  page.on('request', onRequest);
  page.on('response', onResponse);
  page.on('requestfailed', onRequestFailed);
  page.on('console', onConsole);
  page.on('pageerror', onPageError);

  return {
    events,
    consoleLogs,
    dispose() {
      page.off('request', onRequest);
      page.off('response', onResponse);
      page.off('requestfailed', onRequestFailed);
      page.off('console', onConsole);
      page.off('pageerror', onPageError);
    },
  };
}


const TEST_RESULT_SCHEMA_VERSION = 'janus.test-result.v1';
const TEST_RESULT_ID = 'TEST-RUN-2026-05-18-004';
const TEST_RESULT_TITLE = 'Janus Identity and Access Control';

function relativeToWorkspace(filePath) {
  return path.relative(process.cwd(), filePath).replace(/\\/g, '/');
}

function classifyAggregateStatus(results) {
  if (!Array.isArray(results) || results.length === 0) return 'RUNNING';
  if (results.some((entry) => entry.result === 'FAIL')) return 'FAIL';
  if (results.some((entry) => entry.result === 'BLOCKED')) return 'BLOCKED';
  if (results.some((entry) => entry.result === 'MANUAL_GATE_REQUIRED')) return 'PARTIAL';
  if (results.every((entry) => entry.result === 'PASS')) return 'PASS';
  return 'PARTIAL';
}

function writeTestResultSummary(resultDir) {
  const evidenceFiles = fs
    .readdirSync(resultDir)
    .filter((name) => name.endsWith('_evidence.json'))
    .sort();
  const results = [];

  for (const fileName of evidenceFiles) {
    const fullPath = path.join(resultDir, fileName);
    try {
      const payload = JSON.parse(fs.readFileSync(fullPath, 'utf-8'));
      results.push({
        testCaseId: payload.testCaseId || fileName.replace(/_evidence\.json$/, ''),
        result: payload.result || 'UNKNOWN',
        classification: payload.classification || 'UNKNOWN',
        evidencePath: relativeToWorkspace(fullPath),
        durationMs: payload.durationMs || 0,
        notes: payload.notes || '',
        timestamp: payload.timestamp || '',
      });
    } catch (error) {
      results.push({
        testCaseId: fileName.replace(/_evidence\.json$/, ''),
        result: 'BLOCKED',
        classification: 'EVIDENCE_PARSE_ERROR',
        evidencePath: relativeToWorkspace(fullPath),
        durationMs: 0,
        notes: String((error && error.message) || error),
        timestamp: new Date().toISOString(),
      });
    }
  }

  const summary = {
    total: results.length,
    passed: results.filter((entry) => entry.result === 'PASS').length,
    failed: results.filter((entry) => entry.result === 'FAIL').length,
    blocked: results.filter((entry) => entry.result === 'BLOCKED').length,
    manualGateRequired: results.filter((entry) => entry.result === 'MANUAL_GATE_REQUIRED').length,
  };
  const resultJson = path.join(process.cwd(), 'documentation/test-results/TEST-RUN-2026-05-18-004_results.json');
  const aggregate = {
    schemaVersion: TEST_RESULT_SCHEMA_VERSION,
    testRunId: TEST_RESULT_ID,
    title: TEST_RESULT_TITLE,
    status: classifyAggregateStatus(results),
    summary,
    artifacts: {
      resultDirectory: relativeToWorkspace(resultDir),
      resultJson: relativeToWorkspace(resultJson),
      evidenceFiles: evidenceFiles.map((name) => relativeToWorkspace(path.join(resultDir, name))),
    },
    results,
    updatedAt: new Date().toISOString(),
  };
  fs.writeFileSync(resultJson, JSON.stringify(aggregate, null, 2));
  return aggregate;
}

function writeEvidence(testCaseId, result, classification, evidence, notes) {
  const resultDir = path.join(process.cwd(), 'documentation/test-results/TEST-RUN-2026-05-18-004');
  if (!fs.existsSync(resultDir)) {
    fs.mkdirSync(resultDir, { recursive: true });
  }
  const resultFile = path.join(resultDir, `${testCaseId}_evidence.json`);
  const payload = {
    testRunId: 'TEST-RUN-2026-05-18-004',
    testCaseId,
    result,
    classification,
    prompt: evidence?.prompt || '',
    response: evidence?.response || '',
    networkEvents: evidence?.networkEvents || [],
    consoleErrors: evidence?.consoleErrors || [],
    uiState: evidence?.uiState || {},
    durationMs: evidence?.durationMs || 0,
    strategyVersions: evidence?.strategyVersions || {},
    notes: notes || '',
    timestamp: new Date().toISOString(),
  };
  fs.writeFileSync(resultFile, JSON.stringify(payload, null, 2));
  writeTestResultSummary(resultDir);
}

function buildEvidence(prompt, responseText, durationMs, triggeredTools) {
  return {
    prompt,
    response: responseText || '',
    networkEvents: [],
    consoleErrors: [],
    uiState: {},
    durationMs: durationMs || 0,
    triggeredTools: Array.isArray(triggeredTools) ? triggeredTools : [],
    strategyVersions: {
      send: 'chat_button_click_send_v1',
      wait: 'assistant_stream_complete_v1',
      evidence: 'capture_network_v1',
      evaluate: 'contains_any_v1',
      modelSelect: 'model_selection_v2_5',
    },
  };
}


async function runPromptInChatWindow(page, prompt, windowName) {
  // BACKLOG-029 (ATOMIC SCOPE FIX): `windowName` is now an explicit function
  // parameter rather than a generator-time-interpolated string. The call site
  // passes the resolved chat-window id (e.g. 'A') from the TestPlan; every
  // selector / locator below uses the parameter via plain string concatenation,
  // so no runtime template-literal can ever reach an undefined identifier.
  const diagnostics = createPromptDiagnostics(page);
  const input = chatInput(page, windowName);
  let streamRequestCount = 0;
  let streamRequestUrl = null;

  // BACKLOG-028: Tool-Routing-Verification.
  // The backend emits each tool execution as an SSE `tool_result` event with the
  // tool name attached via ev.metadata.name (see backend/api/routers/chat.py).
  // We capture every matching stream Response on this page and, after the bubble
  // has fully rendered, parse the response body for tool names. This is more
  // robust than scraping browser console logs (Janus does not emit a stable
  // `TOOL CALL ATTEMPT:` marker) and works regardless of send strategy.
  const triggeredTools = [];
  const capturedStreamResponses = [];

  const onStreamRequest = (request) => {
    const url = request.url();
    if (request.method() === 'POST' && /\/api\/chat\/stream\/?(\?|$)/.test(new URL(url).pathname)) {
      streamRequestCount++;
      streamRequestUrl = url;
    }
  };
  const onAnyResponse = (response) => {
    try {
      if (response.request().method() !== 'POST') return;
      if (!/\/api\/chat\/stream\/?(\?|$)/.test(new URL(response.url()).pathname)) return;
      capturedStreamResponses.push(response);
    } catch (_) { /* invalid url - ignore */ }
  };
  page.on('request', onStreamRequest);
  page.on('response', onAnyResponse);

  try {
    // Focus window and ensure input visible
    await chatWindow(page, windowName).click();
    await expect(input).toBeVisible({ timeout: 5000 });

    // SEND STRATEGY: chat_button_click_send_v1
    // Promise.all pattern: register stream listener BEFORE the click to eliminate
    // the race window where a fast SSE response could resolve before waitForResponse() attaches.
    // pressSequentially simulates real typing so the frontend's per-keystroke validation
    // (text present + model selected) flips the send button into the enabled state.
    await input.click();
    await input.pressSequentially(prompt, { delay: 30 });

    // DIAGNOSTIC: verify the textarea actually holds the prompt and the send button is enabled.
    // If either fails, the frontend submit handler will bail out at `if (!promptText) return;`
    // and no /api/chat/stream request can ever fire.
    const sendBtnLoc = page.locator('#send-button-' + windowName);
    const preClickDiag = await page.evaluate((w) => {
      const ta = document.getElementById('user-input-' + w);
      const btn = document.getElementById('send-button-' + w);
      const form = document.getElementById('chat-form-' + w);
      const taRect = ta?.getBoundingClientRect?.();
      const btnRect = btn?.getBoundingClientRect?.();
      return {
        textareaFound: !!ta,
        textareaValue: ta?.value ?? null,
        textareaValueLen: (ta?.value ?? '').length,
        textareaTrimmedLen: ((ta?.value ?? '').trim()).length,
        textareaVisible: !!(taRect && taRect.width > 0 && taRect.height > 0),
        buttonFound: !!btn,
        buttonDisabled: btn?.disabled ?? null,
        buttonAriaDisabled: btn?.getAttribute?.('aria-disabled') ?? null,
        buttonType: btn?.type ?? null,
        buttonVisible: !!(btnRect && btnRect.width > 0 && btnRect.height > 0),
        formFound: !!form,
        buttonInForm: !!(btn && form && form.contains(btn)),
        activeElementId: document.activeElement?.id ?? null,
        bodyHasOverlay: !!document.querySelector('.modal-overlay:not([hidden]), .modal.show, [aria-modal="true"]'),
        overlayDetails: Array.from(document.querySelectorAll('.modal-overlay:not([hidden]), .modal.show, [aria-modal="true"]')).map((el) => ({
          tag: el.tagName,
          id: el.id || null,
          classes: el.className || null,
          ariaModal: el.getAttribute('aria-modal'),
          hidden: el.hasAttribute('hidden'),
          rect: (() => { const r = el.getBoundingClientRect(); return { x: r.x, y: r.y, w: r.width, h: r.height }; })(),
          zIndex: getComputedStyle(el).zIndex,
          pointerEvents: getComputedStyle(el).pointerEvents,
          displayed: getComputedStyle(el).display,
        })),
        sendBtnTopElement: (() => {
          const btn = document.getElementById('send-button-' + w);
          if (!btn) return null;
          const r = btn.getBoundingClientRect();
          const cx = r.left + r.width / 2;
          const cy = r.top + r.height / 2;
          const top = document.elementFromPoint(cx, cy);
          if (!top) return null;
          return { tag: top.tagName, id: top.id || null, classes: top.className || null, isBtn: top === btn };
        })(),
      };
    }, windowName);
    console.log('[E2E-DIAG] preClick:', JSON.stringify(preClickDiag));
    if (preClickDiag.textareaTrimmedLen === 0) {
      throw new Error('RUNNER_PRECLICK_EMPTY: textarea #user-input-' + windowName + ' is empty after pressSequentially. ' + JSON.stringify(preClickDiag));
    }
    if (!preClickDiag.buttonInForm) {
      throw new Error('RUNNER_PRECLICK_DOM_BROKEN: #send-button-' + windowName + ' is not nested inside #chat-form-' + windowName + '. ' + JSON.stringify(preClickDiag));
    }

    // CRITICAL FIX: dock-bar (position: fixed; bottom: 0; z-index: 90) geometrically overlaps
    // the send button in the test viewport. Coordinate-based click({force:true}) lands on
    // #dock-bar and never reaches the resolved #send-button-<windowName>. Use DOM-level
    // HTMLElement.click() via evaluate(), which dispatches the click event directly on the
    // target element and triggers native form submission regardless of what sits on top
    // geometrically.
    const [streamResponse] = await Promise.all([
      page.waitForResponse(
        (res) => res.url().includes('/api/chat/stream') && res.status() === 200,
        { timeout: STREAM_REQUEST_TIMEOUT_MS },
      ),
      sendBtnLoc.evaluate((btn) => btn.click()),
    ]);
    void streamResponse;

    // Patient polling: wait until the assistant bubble holds real content,
    // not just the "..." loading placeholder (which may carry an appended timestamp).
    try {
      await expect(async () => {
        const bubble = page.locator('#chat-messages-' + windowName + ' .message.assistant').last();
        await expect(bubble).toBeVisible();
        const text = await bubble.innerText();
        const trimmed = text.trim();
        if (trimmed.startsWith('...')) throw new Error('Still loading');
        expect(trimmed.length).toBeGreaterThan(15);
      }).toPass({ timeout: ASSISTANT_RESPONSE_TIMEOUT_MS });
    } catch (_) {
      throw new Error('RUNNER_STREAM_TIMEOUT: Assistant bubble appeared but is empty or only contains "..." with timestamp. SSE stream observed but no real content rendered.');
    }

    const assistantMessage = assistantResponse(page, windowName);

    // Verify stream request was actually observed (bubble without stream = frontend bug)
    if (streamRequestCount === 0) {
      throw new Error('RUNNER_STREAM_TIMEOUT: Assistant bubble appeared but no POST /api/chat/stream request was observed. Frontend may have rendered static content without backend call.');
    }

    // Tool-loop responses can briefly render provider tool-call JSON before the
    // final natural-language synthesis replaces it. Do not evaluate that
    // intermediate bubble text; wait for observed SSE streams to finish first.
    for (const captured of capturedStreamResponses) {
      try {
        await Promise.race([
          typeof captured.finished === 'function' ? captured.finished() : Promise.resolve(),
          new Promise((_, reject) => setTimeout(() => reject(new Error('stream-finish-timeout')), 15000)),
        ]);
      } catch (_) {
        // Keep the original assistant timeout authoritative. A finish wait
        // timeout should not mask the DOM diagnostics below.
      }
    }
    await page.waitForTimeout(500);

    // Check for visible Janus errors
    const errorMessage = page.locator(
      '#chat-messages-' + windowName + ' .message.error, ' +
      '#chat-messages-' + windowName + ' .message.system'
    ).last();
    const hasError = await errorMessage.count() > 0;
    if (hasError) {
      const errorText = await errorMessage.textContent();
      throw new Error(`PROVIDER_TIMEOUT: Visible Janus error bubble: ${errorText}`);
    }

    const responseText = await assistantMessage.textContent();

    // BACKLOG-028: Parse the captured SSE stream body and extract tool names.
    // `response.body()` on an SSE stream resolves only when the stream closes;
    // by this point the assistant bubble has already rendered, so the stream
    // has emitted its `done` event and `body()` returns immediately.
    for (const captured of capturedStreamResponses) {
      let text = '';
      try {
        const buf = await Promise.race([
          captured.body(),
          new Promise((_, reject) => setTimeout(() => reject(new Error('body-timeout')), 5000)),
        ]);
        text = Buffer.isBuffer(buf) ? buf.toString('utf-8') : String(buf || '');
      } catch (_) {
        continue;
      }
      const blocks = text.split(/\r?\n\r?\n/);
      for (const block of blocks) {
        const dataLines = block.split(/\r?\n/).filter((l) => l.startsWith('data:'));
        if (dataLines.length === 0) continue;
        const jsonStr = dataLines.map((l) => l.replace(/^data:\s*/, '')).join('');
        if (!jsonStr) continue;
        try {
          const parsed = JSON.parse(jsonStr);
          if (!parsed || typeof parsed !== 'object') continue;
          // `tool_result` is the canonical event today; `tool_call`/`tool_start`
          // are reserved for future backend instrumentation.
          if ((parsed.type === 'tool_result' || parsed.type === 'tool_call' || parsed.type === 'tool_start') &&
              typeof parsed.name === 'string' && parsed.name.length > 0) {
            triggeredTools.push(parsed.name);
          }
        } catch (_) { /* non-JSON event line - ignore */ }
      }
    }

    return { responseText: responseText || '', triggeredTools };
  } catch (error) {
    const apiEvents = diagnostics.events.filter((event) => event.url);
    const chatEvents = apiEvents.filter((event) => /\/api\/.*(chat|message)/i.test(event.url));
    const streamEvents = apiEvents.filter((event) => /\/api\/chat\/stream/i.test(event.url));
    const failedEvents = diagnostics.events.filter(
      (event) => event.type === 'requestfailed' || event.type === 'pageerror' || event.type.startsWith('console:')
    );
    const sendMessageLogs = diagnostics.consoleLogs.filter((log) => log.text.includes('[sendMessage]'));
    const sseLogs = diagnostics.consoleLogs.filter((log) => log.text.includes('[SSE'));

    // DOM diagnostics: capture chat-messages state even when page is still open
    let domDump = 'N/A';
    let messageTexts = 'N/A';
    let domEval = 'N/A';
    try {
      // FIX (BACKLOG-025 / BACKLOG-027 / BACKLOG-029 / BACKLOG-030): the chat-window
      // identifier is accessed exclusively via the function parameter `windowName`,
      // never via any generator-time identifier. The original undefined-chat-window
      // ReferenceError class of bug is now structurally impossible to reintroduce
      // because the generator-side variable has been renamed to `genTargetWin` and
      // the function parameter to `windowName`, so a forgotten escape can no longer
      // emit a bare reference into the spec source.
      const chatMessagesEl = page.locator('#chat-messages-' + windowName).first();
      domDump = await chatMessagesEl.innerHTML({ timeout: 2000 });
      const msgs = await page.locator('#chat-messages-' + windowName + ' .message').all();
      messageTexts = await Promise.all(msgs.map(async (m) => await m.textContent()));
    } catch (e) { messageTexts = 'ERR: ' + String(e?.message || e).slice(0, 200); }
    try {
      domEval = await page.evaluate((w) => {
        const cm = document.getElementById('chat-messages-' + w);
        if (!cm) return { found: false };
        const messages = Array.from(cm.querySelectorAll('.message')).map((m, i) => ({
          i,
          className: m.className,
          bubbleHTMLLen: m.querySelector('.bubble')?.innerHTML?.length ?? 0,
          bubbleTextLen: m.querySelector('.bubble')?.textContent?.length ?? 0,
          bubbleTextSample: (m.querySelector('.bubble')?.textContent ?? '').slice(0, 80),
          isConnected: m.isConnected,
        }));
        return {
          found: true,
          containerChildCount: cm.childElementCount,
          messageCount: messages.length,
          messages,
          containerHTMLLen: cm.innerHTML.length,
          containerHTMLSample: cm.innerHTML.slice(0, 400),
        };
      }, windowName);
    } catch (e) { domEval = 'EVAL_ERR: ' + String(e?.message || e).slice(0, 200); }

    if (page.isClosed()) {
      throw new Error(
        `RUNNER_WAIT_FAILURE: Playwright page closed before completion for prompt "${prompt}".\nChat Events: ${JSON.stringify(chatEvents)}\nStream Events: ${JSON.stringify(streamEvents)}\nFailures: ${JSON.stringify(failedEvents)}\nOriginal: ${error.message}`
      );
    }

    // Re-throw if already classified — but enrich with SSE diagnostics so we can
    // see where the frontend stream-render pipeline actually broke.
    if (/^(RUNNER_|FRONTEND_|BACKEND_|PROVIDER_|TOOL_|ASSERTION_)/.test(error.message)) {
      throw new Error(`${error.message}
Console [SSE]: ${JSON.stringify(sseLogs)}
DOM eval: ${JSON.stringify(domEval)}
DOM message texts: ${JSON.stringify(messageTexts)}`);
    }

    // Distinguish backend/provider errors from runner errors based on stream observation
    if (streamEvents.length === 0) {
      throw new Error(
        `RUNNER_STREAM_TIMEOUT: No POST /api/chat/stream observed after "${prompt}".
Chat Events: ${JSON.stringify(chatEvents)}
Console [sendMessage]: ${JSON.stringify(sendMessageLogs)}
Console [SSE]: ${JSON.stringify(sseLogs)}
Diagnostics: ${JSON.stringify(diagnostics.events)}
DOM messages: ${JSON.stringify(messageTexts)}
Original: ${error.message}`
      );
    }

    throw new Error(
      `PROVIDER_TIMEOUT: Assistant response not received within ${ASSISTANT_RESPONSE_TIMEOUT_MS}ms after "${prompt}". Stream request was observed but no assistant message rendered.
Chat Events: ${JSON.stringify(chatEvents)}
Stream Events: ${JSON.stringify(streamEvents)}
Failures: ${JSON.stringify(failedEvents)}
Console [SSE]: ${JSON.stringify(sseLogs)}
DOM dump: ${domDump.slice(0, 1200)}
DOM message texts: ${JSON.stringify(messageTexts)}
Original: ${error.message}`
    );
  } finally {
    page.off('request', onStreamRequest);
    page.off('response', onAnyResponse);
    diagnostics.dispose();
  }
}

